\begin{align*}
D&=\begin{vmatrix}0&-1&0&0\\x^2&x&-1&0\\0&0&x&-1\\a_4 + a_3x&a_3&a_2&x + a_1\end{vmatrix}\\
&=\begin{vmatrix}0&-1&0&0\\0&x&-1&0\\x^3&0&x&-1\\a_4 + a_3x + a_2x^2&a_3&a_2&x + a_1\end{vmatrix}\\
&=\begin{vmatrix}0&-1&0&0\\0&x&-1&0\\0&0&x&-1\\a_4 + a_3x + a_2x^2 + a_1x^3 + x^4&a_3&a_2&x + a_1\end{vmatrix}
\end{align*}
