\textbf{\textcolor{red}{方法一：(初等变换)}}
\begin{align*}
\begin{bmatrix}
\boldsymbol{A} + \boldsymbol{B} \\
\boldsymbol{B}
\end{bmatrix} &\to
\begin{bmatrix}
\boldsymbol{A} \\
\boldsymbol{B}
\end{bmatrix}\\
\text{故 }r(\boldsymbol{A} + \boldsymbol{B}) &\leq r\begin{bmatrix}
\boldsymbol{A} + \boldsymbol{B} \\
\boldsymbol{B}
\end{bmatrix} = r\begin{bmatrix}
\boldsymbol{A} \\
\boldsymbol{B}
\end{bmatrix} = r\begin{bmatrix}
\boldsymbol{A} \\
\boldsymbol{B}
\end{bmatrix}^{\mathrm{T}}\\
&= r(\boldsymbol{A}^{\mathrm{T}}, \boldsymbol{B}^{\mathrm{T}}) \leq r(\boldsymbol{A}^{\mathrm{T}}) + r(\boldsymbol{B}^{\mathrm{T}})\\
&= r(\boldsymbol{A}) + r(\boldsymbol{B})
\end{align*}
\textbf{\textcolor{red}{方法二：(三秩相等)}}
设$r(\boldsymbol{A}) = r$，极大线性无关组为$\boldsymbol{\alpha}_{i_1}, \boldsymbol{\alpha}_{i_2}, \cdots, \boldsymbol{\alpha}_{i_r}$；$r(\boldsymbol{B}) = t$，极大线性无关为$\boldsymbol{\beta}_{j_1}, \boldsymbol{\beta}_{j_2}, \cdots, \boldsymbol{\beta}_{j_t}$。
\[
\boldsymbol{A} + \boldsymbol{B} = (\boldsymbol{\alpha}_1 + \boldsymbol{\beta}_1, \boldsymbol{\alpha}_2 + \boldsymbol{\beta}_2, \cdots, \boldsymbol{\alpha}_n + \boldsymbol{\beta}_n)
\]
所以$\boldsymbol{\alpha}_1 + \boldsymbol{\beta}_1, \boldsymbol{\alpha}_2 + \boldsymbol{\beta}_2, \cdots, \boldsymbol{\alpha}_n + \boldsymbol{\beta}_n$可由$\boldsymbol{\alpha}_{i_1}, \boldsymbol{\alpha}_{i_2}, \cdots, \boldsymbol{\alpha}_{i_r}, \boldsymbol{\beta}_{j_1}, \boldsymbol{\beta}_{j_2}, \cdots, \boldsymbol{\beta}_{j_t}$线性表出。故
\begin{align*}
r(\boldsymbol{A} + \boldsymbol{B}) &= r(\boldsymbol{\alpha}_1 + \boldsymbol{\beta}_1, \boldsymbol{\alpha}_2 + \boldsymbol{\beta}_2, \cdots, \boldsymbol{\alpha}_n + \boldsymbol{\beta}_n) \leq r(\boldsymbol{\alpha}_{i_1}, \boldsymbol{\alpha}_{i_2}, \cdots, \boldsymbol{\alpha}_{i_r}, \boldsymbol{\beta}_{j_1}, \boldsymbol{\beta}_{j_2}, \cdots, \boldsymbol{\beta}_{j_t})\\
&\leq r + t = r(\boldsymbol{A}) + r(\boldsymbol{B})
\end{align*}

\textbf{\textcolor{red}{方法一：（三秩相等）}}
\[
AB = [\alpha_1, \alpha_2, \cdots, \alpha_n]
\begin{bmatrix}
b_{11} & \cdots & b_{1s} \\
b_{21} & \cdots & b_{2s} \\
\vdots & & \vdots \\
b_{n1} & \cdots & b_{ns}
\end{bmatrix}
= [\gamma_1, \gamma_2, \cdots, \gamma_s]
\]
$AB$的列向量可由$\alpha_1, \alpha_2, \cdots, \alpha_n$线性表示，即$AB$的列向量可由$A$的列向量线性表示，故$r(AB)=AB$的列秩$\leq A$的列秩$= r(A)$。
取$B$的行向量，$A$作为矩阵左乘，同理可得$r(AB)\leq r(B)$。
\textbf{\textcolor{red}{方法二：（初等行变换法，见$P68$性质$5$）}}

先正交化：
\begin{align*}
\boldsymbol{\beta}_1&=\boldsymbol{\alpha}_1=\begin{pmatrix}1\\2\\-1\end{pmatrix}\\
\boldsymbol{\beta}_2&=\boldsymbol{\alpha}_2-\frac{(\boldsymbol{\alpha}_2,\boldsymbol{\beta}_1)}{(\boldsymbol{\beta}_1,\boldsymbol{\beta}_1)}\boldsymbol{\beta}_1=\begin{pmatrix}-1\\3\\1\end{pmatrix}-\frac{4}{6}\begin{pmatrix}1\\2\\-1\end{pmatrix}=\frac{1}{3}\begin{pmatrix}-5\\5\\5\end{pmatrix}=\frac{5}{3}\begin{pmatrix}-1\\1\\1\end{pmatrix}\\
\boldsymbol{\beta}_3&=\boldsymbol{\alpha}_3-\frac{(\boldsymbol{\alpha}_3,\boldsymbol{\beta}_1)}{(\boldsymbol{\beta}_1,\boldsymbol{\beta}_1)}\boldsymbol{\beta}_1-\frac{(\boldsymbol{\alpha}_3,\boldsymbol{\beta}_2)}{(\boldsymbol{\beta}_2,\boldsymbol{\beta}_2)}\boldsymbol{\beta}_2=\begin{pmatrix}4\\-1\\0\end{pmatrix}-\frac{2}{6}\begin{pmatrix}1\\2\\-1\end{pmatrix}+\frac{5}{3}\begin{pmatrix}-1\\1\\1\end{pmatrix}=2\begin{pmatrix}1\\0\\1\end{pmatrix}
\end{align*}
再单位化：
\[
\boldsymbol{\gamma}_1=\frac{1}{\sqrt{6}}\begin{pmatrix}1\\2\\-1\end{pmatrix},\boldsymbol{\gamma}_2=\frac{1}{\sqrt{3}}\begin{pmatrix}-1\\1\\1\end{pmatrix},\boldsymbol{\gamma}_3=\frac{1}{\sqrt{2}}\begin{pmatrix}1\\0\\1\end{pmatrix}
\]

已知$\boldsymbol{A}$为正交矩阵且$a_{11}=1$，可知$\boldsymbol{A}$的第一列为$\begin{pmatrix}1\\0\\0\end{pmatrix}$，第一行为$(1,0,0)$。因此
\[
\boldsymbol{A}=\begin{bmatrix}
1 & 0 & 0 \\
0 & a_{22} & a_{23} \\
0 & a_{32} & a_{33}
\end{bmatrix}
\]
$\boldsymbol{A}$是正交矩阵，故$\boldsymbol{A}$可逆. 方程组$\boldsymbol{A}\boldsymbol{x}=\boldsymbol{b}$的解是唯一的.
显然
\[
\boldsymbol{A}\boldsymbol{x}=\begin{bmatrix}
1 & 0 & 0 \\
0 & a_{22} & a_{32} \\
0 & a_{23} & a_{33}
\end{bmatrix}\begin{pmatrix}1\\0\\0\end{pmatrix}=\begin{pmatrix}1\\0\\0\end{pmatrix}=\boldsymbol{b}
\]
因此方程组的唯一解为
\[
\boldsymbol{x}=\begin{pmatrix}1\\0\\0\end{pmatrix}
\]

二次型矩阵为
\[
A =
\begin{bmatrix}
1 & 2 & 2 \\
2 & 1 & 2 \\
2 & 2 & 1
\end{bmatrix}
\]
由特征多项式
\[
|\lambda E - A| =
\begin{vmatrix}
\lambda - 1 & -2 & -2 \\
-2 & \lambda - 1 & -2 \\
-2 & -2 & \lambda - 1
\end{vmatrix}
= (\lambda - 5)(\lambda + 1)^2
\]
$A$的特征值：$5$，$-1$，$-1$。
当$\lambda = 5$时，由$(5E - A)x = 0$，可得
\[
\begin{bmatrix}
4 & -2 & -2 \\
-2 & 4 & -2 \\
-2 & -2 & 4
\end{bmatrix}
\to
\begin{bmatrix}
1 & 0 & -1 \\
0 & 1 & -1 \\
0 & 0 & 0
\end{bmatrix}
\]
得$\alpha_1 = (1,1,1)^T$。
当$\lambda = -1$时，由$(-E - A)x = 0$，可得
\[
\begin{bmatrix}
-2 & -2 & -2 \\
-2 & -2 & -2 \\
-2 & -2 & -2
\end{bmatrix}
\to
\begin{bmatrix}
1 & 1 & 1 \\
0 & 0 & 0 \\
0 & 0 & 0
\end{bmatrix}
\]
得$\alpha_2 = (-1,1,0)^T$，$\alpha_3 = (-1,0,1)^T$。
将$\alpha_2,\alpha_3$进行施密特正交化
\[
\beta_2 = \alpha_2 =
\begin{bmatrix}
-1 \\
1 \\
0
\end{bmatrix}
\]
\[
\beta_3 = \alpha_3 - \frac{(\alpha_3,\beta_2)}{(\beta_2,\beta_2)}\beta_2 =
\begin{bmatrix}
-1 \\
0 \\
1
\end{bmatrix}
- \frac{1}{2}
\begin{bmatrix}
-1 \\
1 \\
0
\end{bmatrix}
= \frac{1}{2}
\begin{bmatrix}
-1 \\
-1 \\
2
\end{bmatrix}
\]
单位化：
\[
\gamma_1 = \frac{1}{\sqrt{3}}
\begin{bmatrix}
1 \\
1 \\
1
\end{bmatrix}
,
\gamma_2 = \frac{1}{\sqrt{2}}
\begin{bmatrix}
-1 \\
1 \\
0
\end{bmatrix}
,
\gamma_3 = \frac{1}{\sqrt{6}}
\begin{bmatrix}
-1 \\
-1 \\
2
\end{bmatrix}
\]
令
\[
P = (\gamma_1,\gamma_2,\gamma_3) =
\begin{bmatrix}
\frac{1}{\sqrt{3}} & -\frac{1}{\sqrt{2}} & -\frac{1}{\sqrt{6}} \\
\frac{1}{\sqrt{3}} & \frac{1}{\sqrt{2}} & -\frac{1}{\sqrt{6}} \\
\frac{1}{\sqrt{3}} & 0 & \frac{2}{\sqrt{6}}
\end{bmatrix}
\]
则$P^{-1}AP = \Lambda =
\begin{bmatrix}
5 & 0 & 0 \\
0 & -1 & 0 \\
0 & 0 & -1
\end{bmatrix}
$。
那么二次型$x^TAx$经正交变换
\[
\begin{bmatrix}
x_1 \\
x_2 \\
x_3
\end{bmatrix}
=
\begin{bmatrix}
\frac{1}{\sqrt{3}} & -\frac{1}{\sqrt{2}} & -\frac{1}{\sqrt{6}} \\
\frac{1}{\sqrt{3}} & \frac{1}{\sqrt{2}} & -\frac{1}{\sqrt{6}} \\
\frac{1}{\sqrt{3}} & 0 & \frac{2}{\sqrt{6}}
\end{bmatrix}
\begin{bmatrix}
y_1 \\
y_2 \\
y_3
\end{bmatrix}
\]
化为标准形
\[
f = x^TAx = y^T\Lambda y = 5y_1^2 - y_2^2 - y_3^2
\]
